**Function 3: `createOrder(input: CreateOrderInput)`**

This is the most complex function. It must validate input, check stock for each item, deduct stock, build the order, and push it to the orders array. The error messages must match exactly.

```typescript
export function createOrder(input: CreateOrderInput) {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ServiceError(400, "userId and items are required");
  }

  if (input.items.length === 0) {
    throw new ServiceError(400, "Order must have at least one item");
  }

  const orderItems: import("../types.js").OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new ServiceError(400, `Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new ServiceError(400, "Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new ServiceError(400, `Insufficient stock for ${product.name}`);
    }

    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending" as const,
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}
```

Note: The `OrderItem` type import can use a regular import at the top of the file instead of the inline `import(...)` syntax. I used the inline form above just for illustration. The actual implementation should use:

```typescript
