```

**Function 4: `updateOrderStatus(id: number, status: string)`**

```typescript
const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"];

const TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

export function updateOrderStatus(id: number, status: string) {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    throw new ServiceError(404, "Order not found");
  }

  if (!VALID_STATUSES.includes(status)) {
    throw new ServiceError(
      400,
      `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`,
    );
  }

  if (!TRANSITIONS[order.status]?.includes(status)) {
    throw new ServiceError(
      400,
      `Cannot transition from ${order.status} to ${status}`,
    );
  }

  order.status = status as typeof order.status;

  return order;
}
```

The `VALID_STATUSES` and `TRANSITIONS` constants are promoted to module-level. They are business rules, so they belong in the service, not the route handler.

