  const { category, minPrice, maxPrice } = req.query;

  const filters = {
    category: typeof category === "string" ? category : undefined,
    minPrice:
      typeof minPrice === "string" && !isNaN(parseFloat(minPrice))
        ? parseFloat(minPrice)
        : undefined,
    maxPrice:
      typeof maxPrice === "string" && !isNaN(parseFloat(maxPrice))
        ? parseFloat(maxPrice)
        : undefined,
  };

  const result = productService.getProducts(filters);
  res.json(result);
});

router.get("/products/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const result = productService.getProductById(id);
    res.json(result);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.patch("/products/:id/stock", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { adjustment } = req.body as { adjustment: number };

    if (typeof adjustment !== "number") {
      res.status(400).json({ error: "adjustment must be a number" });
      return;
    }

    const result = productService.adjustProductStock(id, adjustment);
    res.json(result);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

export { router as productRouter };
```

Key observations:
- `GET /products` does not need try/catch because `getProducts` never throws. It always returns a result (possibly with an empty products array).
- The `typeof adjustment !== "number"` validation stays in the route handler because it is input type validation (an HTTP concern). The service can trust its typed parameter.
- The error-handling pattern `if (e instanceof ServiceError)` is repeated. This is intentional to keep things simple. A shared error-handling middleware could be added later, but it adds complexity for little benefit with only a few routes.
- The `throw e` re-throw for non-ServiceError exceptions preserves the default Express 500 behavior.

---

#### 3f. `src/routes/orders.ts` (MODIFY -- thin handlers)

```typescript
