import { ServiceError } from "../services/errors.js";
import * as orderService from "../services/orderService.js";

const router = Router();

router.get("/orders", (req, res) => {
  const { userId, status } = req.query;

  const filters = {
    userId:
      typeof userId === "string" && !isNaN(parseInt(userId, 10))
        ? parseInt(userId, 10)
        : undefined,
    status: typeof status === "string" ? status : undefined,
  };

  const result = orderService.getOrders(filters);
  res.json(result);
});

router.get("/orders/:id", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const result = orderService.getOrderById(id);
    res.json(result);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.post("/orders", (req, res) => {
  try {
    const input = req.body as CreateOrderInput;
    const order = orderService.createOrder(input);
    res.status(201).json(order);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

router.patch("/orders/:id/status", (req, res) => {
  try {
    const id = parseInt(req.params.id, 10);
    const { status } = req.body as { status: string };
    const order = orderService.updateOrderStatus(id, status);
    res.json(order);
  } catch (e) {
    if (e instanceof ServiceError) {
      res.status(e.statusCode).json({ error: e.message });
      return;
    }
    throw e;
  }
});

export { router as orderRouter };
```

Notice that routes no longer import `products`, `orders`, or `getNextOrderId` from `../data.js`. All data access goes through the service layer.

---

### 4. Implementation Sequence

The implementation must be done in a specific order to avoid breaking the build at any intermediate step:

**Step 1: Add types to `src/types.ts`**
Add the `ProductFilters` and `OrderFilters` interfaces. This is purely additive and breaks nothing.

**Step 2: Create `src/services/errors.ts`**
Create the `ServiceError` class. This is a new file with no dependents yet.

**Step 3: Create `src/services/productService.ts`**
Create the product service with all three functions. This is a new file -- no existing code depends on it yet. The business logic is copy-pasted from the route handlers and adapted (replace `res.status(...).json(...)` with `throw new ServiceError(...)`, replace `return` with `throw`).

**Step 4: Create `src/services/orderService.ts`**
Same approach as Step 3 for the order service. All four functions.

**Step 5: Refactor `src/routes/products.ts`**
Replace inline business logic with calls to `productService`. Keep query-string parsing in the handler. Add try/catch for error mapping.

**Step 6: Refactor `src/routes/orders.ts`**
Same as Step 5 for orders.

**Step 7: Run tests**
`npx vitest run` -- all 10 tests must pass unchanged.

Steps 1-4 can be done without risk because they only add new files/exports. Steps 5-6 are the swap -- these should be done carefully, one route handler at a time if desired, running tests after each change.

---

### 5. Potential Pitfalls

**Pitfall 1: Error message mismatch.** The tests check HTTP status codes but not error message text (checked via `expect(res.status).toBe(400)`). However, to be safe, the service error messages must be preserved character-for-character. The plan above does this -- every string literal in `ServiceError` constructors matches the original `res.json({ error: "..." })` messages exactly.

**Pitfall 2: The `POST /orders` partial stock deduction problem.** If the `createOrder` service throws mid-loop (e.g., item 2 out of 3 fails), stock has already been deducted for item 1. This is the **exact same behavior** as the current route handler, so it is not a regression. The tests do not test for rollback, and adding rollback is out of scope for this refactoring.

**Pitfall 3: ESM `.js` extensions.** All new imports must use `.js` extensions. For example, `import { ServiceError } from "./errors.js"` -- not `./errors` or `./errors.ts`. The `tsconfig.json` uses `"module": "Node16"` which requires this.

**Pitfall 4: `src/services/` directory must be created** before creating files in it. This is a filesystem concern for whoever implements the plan.

**Pitfall 5: The `GET /products` handler's filter parsing behavior.** The current code checks `if (minPrice && typeof minPrice === "string")` -- this means an empty string `""` is falsy and would skip the filter. The refactored route handler must preserve this: if `minPrice` is an empty string, it should produce `undefined` in the filters object, not `NaN`. The `!isNaN(parseFloat(minPrice))` check in the proposed handler accomplishes this because `parseFloat("")` returns `NaN`.

**Pitfall 6: `import type` vs `import`.** The `CreateOrderInput` and `OrderItem` types should use `import type` since they are only used as type annotations. The `ServiceError` class must use a regular `import` because it is used as a value (`instanceof` check).

---

### 6. What Does NOT Change

- `/src/app.ts` -- no changes needed. It imports routers, which keep the same export names.
- `/src/data.ts` -- no changes. Services import from it directly.
- `/tests/products.test.ts` -- no changes (constraint).
- `/tests/orders.test.ts` -- no changes (constraint).
- `tsconfig.json` -- no changes. The `rootDir: "./src"` already covers `src/services/`.
- `package.json` -- no changes.

---

### 7. Summary of the Responsibility Split

| Concern | Lives in Route Handler | Lives in Service |
|---|---|---|
| Parse `req.params`, `req.query`, `req.body` | Yes | No |
| Coerce strings to numbers (`parseInt`, `parseFloat`) | Yes | No |
| Validate input *types* (e.g., `typeof adjustment !== "number"`) | Yes | No |
| Validate business rules (stock >= 0, valid status transition) | No | Yes |
| Data access (find product, push order) | No | Yes |
| Compute derived fields (isLowStock, inventoryValue, summary) | No | Yes |
| Choose HTTP status code | Yes (from ServiceError.statusCode) | Indirectly (sets statusCode on ServiceError) |
| Format response JSON | Yes (trivially: `res.json(result)`) | Shapes the return object |

