    const res = await request(app)
      .post("/orders")
      .send({
        userId: 1,
        items: [{ productId: 999, quantity: 1 }],
      });
    expect(res.status).toBe(400);
  });
});

describe("PATCH /orders/:id/status", () => {
  it("should update order status", async () => {
    const res = await request(app)
      .patch("/orders/2/status")
